def solve():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    idx = 1
    results = []

    for _ in range(t):
        n = int(data[idx])
        a = data[idx + 1]
        b = data[idx + 2]
        idx += 3

        if a == b:
            results.append(0)
            continue

        if '1' not in a:
            results.append(-1)
            continue

        count_a1 = a.count('1')
        count_b1 = b.count('1')

        if count_a1 == 0:
            if count_b1 == 0:
                results.append(0)
            else:
                results.append(-1)
            continue

        possible = False
        min_ops = float('inf')

        # Case 1: No flip
        if count_b1 == count_a1:
            possible = True
            ops = 0
            for i in range(n):
                if a[i] != b[i]:
                    ops += 1
            if ops % 2 == 0:
                min_ops = min(min_ops, ops)

        # Case 2: Flip
        if count_b1 == n - count_a1 + 1:
            possible = True
            ops = 1
            for i in range(n):
                if a[i] == b[i]:
                    ops += 1
            if ops % 2 == 1:
                min_ops = min(min_ops, ops)

        if possible:
            results.append(min_ops)
        else:
            results.append(-1)

    for result in results:
        print(result)

